__all__ = ['CREATE_INVITE_GQL', 'CREATE_PROJECT_GQL', 'CREATE_SERVICE_ACCOUNT_GQL', 'CREATE_TEAM_GQL', 'CREATE_USER_FROM_ADMIN_GQL', 'DELETE_API_KEY_GQL', 'DELETE_INVITE_GQL', 'GENERATE_API_KEY_GQL', 'GET_AGENT_RUNS_GQL', 'GET_DEFAULT_ENTITY_GQL', 'GET_PROJECTS_GQL', 'GET_PROJECT_GQL', 'GET_SWEEPS_GQL', 'GET_SWEEP_AGENTS_GQL', 'GET_SWEEP_AGENT_GQL', 'GET_SWEEP_GQL', 'GET_SWEEP_LEGACY_GQL', 'GET_TEAM_ENTITY_GQL', 'GET_VIEWER_GQL', 'IS_PROJECT_READ_ONLY_GQL', 'SEARCH_USERS_GQL']
GET_PROJECTS_GQL = '\nquery GetProjects($entity: String, $cursor: String, $perPage: Int = 50) {\n  models(entityName: $entity, after: $cursor, first: $perPage) {\n    pageInfo {\n      ...PageInfoFragment\n    }\n    edges {\n      node {\n        ...ProjectFragment\n      }\n    }\n  }\n}\n\nfragment ApiKeyFragment on ApiKey {\n  id\n  name\n  description\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n\nfragment ProjectFragment on Project {\n  __typename\n  id\n  name\n  entityName\n  createdAt\n  isBenchmark\n  user {\n    ...UserFragment\n  }\n}\n\nfragment UserFragment on User {\n  id\n  name\n  username\n  email\n  admin\n  flags\n  entity\n  deletedAt\n  apiKeys {\n    edges {\n      node {\n        ...ApiKeyFragment\n      }\n    }\n  }\n  teams {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
GET_PROJECT_GQL = '\nquery GetProject($name: String!, $entity: String!) {\n  project(name: $name, entityName: $entity) {\n    ...ProjectFragment\n  }\n}\n\nfragment ApiKeyFragment on ApiKey {\n  id\n  name\n  description\n}\n\nfragment ProjectFragment on Project {\n  __typename\n  id\n  name\n  entityName\n  createdAt\n  isBenchmark\n  user {\n    ...UserFragment\n  }\n}\n\nfragment UserFragment on User {\n  id\n  name\n  username\n  email\n  admin\n  flags\n  entity\n  deletedAt\n  apiKeys {\n    edges {\n      node {\n        ...ApiKeyFragment\n      }\n    }\n  }\n  teams {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
CREATE_PROJECT_GQL = '\nmutation CreateProject($input: UpsertModelInput!) {\n  result: upsertModel(input: $input) {\n    project {\n      ...CreatedProjectFragment\n    }\n    model {\n      ...CreatedProjectFragment\n    }\n    inserted\n  }\n}\n\nfragment CreatedProjectFragment on Project {\n  id\n  name\n  entityName\n  description\n  access\n  views\n}\n'
IS_PROJECT_READ_ONLY_GQL = '\nquery IsProjectReadOnly($entity: String!, $project: String!) {\n  project(entityName: $entity, name: $project) {\n    readOnly\n  }\n}\n'
GET_SWEEPS_GQL = '\nquery GetSweeps($project: String!, $entity: String!, $filters: JSONString!, $cursor: String, $perPage: Int = 50) {\n  project(name: $project, entityName: $entity) {\n    totalSweeps\n    sweeps(after: $cursor, first: $perPage, filters: $filters) {\n      pageInfo {\n        ...PageInfoFragment\n      }\n      edges {\n        node {\n          ...SweepFragment\n        }\n      }\n    }\n  }\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n\nfragment SweepFragment on Sweep {\n  __typename\n  id\n  name\n  displayName\n  method\n  state\n  description\n  bestLoss\n  config\n  createdAt\n  updatedAt\n  runCount\n  runCountExpected\n}\n'
GET_SWEEP_GQL = '\nquery GetSweep($name: String!, $project: String, $entity: String) {\n  project(name: $project, entityName: $entity) {\n    sweep(sweepName: $name) {\n      ...SweepFragment\n    }\n  }\n}\n\nfragment SweepFragment on Sweep {\n  __typename\n  id\n  name\n  displayName\n  method\n  state\n  description\n  bestLoss\n  config\n  createdAt\n  updatedAt\n  runCount\n  runCountExpected\n}\n'
GET_SWEEP_LEGACY_GQL = '\nquery GetSweepLegacy($name: String!, $project: String, $entity: String) {\n  project(name: $project, entityName: $entity) {\n    sweep(sweepName: $name) {\n      ...LegacySweepFragment\n    }\n  }\n}\n\nfragment LegacySweepFragment on Sweep {\n  __typename\n  id\n  name\n  state\n  bestLoss\n  config\n}\n'
GET_SWEEP_AGENT_GQL = '\nquery GetSweepAgent($agentID: String!, $sweep: String!, $entity: String, $project: String) {\n  project(name: $project, entityName: $entity) {\n    sweep(sweepName: $sweep) {\n      agent(agentName: $agentID) {\n        ...AgentFragment\n      }\n    }\n  }\n}\n\nfragment AgentFragment on Agent {\n  id\n  name\n  host\n  state\n  totalRuns\n  createdAt\n  heartbeatAt\n}\n'
GET_SWEEP_AGENTS_GQL = '\nquery GetSweepAgents($sweep: String!, $entity: String, $project: String) {\n  project(name: $project, entityName: $entity) {\n    sweep(sweepName: $sweep) {\n      agents {\n        edges {\n          node {\n            ...AgentFragment\n          }\n        }\n      }\n    }\n  }\n}\n\nfragment AgentFragment on Agent {\n  id\n  name\n  host\n  state\n  totalRuns\n  createdAt\n  heartbeatAt\n}\n'
GET_AGENT_RUNS_GQL = '\nquery GetAgentRuns($agentID: String!, $sweep: String!, $entity: String, $project: String, $after: String, $before: String, $first: Int, $last: Int, $order: String) {\n  project(name: $project, entityName: $entity) {\n    sweep(sweepName: $sweep) {\n      agent(agentName: $agentID) {\n        runs(after: $after, before: $before, first: $first, last: $last, order: $order) {\n          pageInfo {\n            ...PageInfoFragment\n          }\n          edges {\n            cursor\n            node {\n              ...LightweightRunFragment\n            }\n          }\n        }\n      }\n    }\n  }\n}\n\nfragment LightweightRunFragment on Run {\n  id\n  tags\n  name\n  displayName\n  sweepName\n  state\n  group\n  jobType\n  commit\n  readOnly\n  createdAt\n  heartbeatAt\n  description\n  notes\n  historyLineCount\n  user {\n    name\n    username\n  }\n}\n\nfragment PageInfoFragment on PageInfo {\n  __typename\n  endCursor\n  hasNextPage\n}\n'
GET_TEAM_ENTITY_GQL = '\nquery GetTeamEntity($name: String!) {\n  entity(name: $name) {\n    id\n    name\n    available\n    photoUrl\n    readOnly\n    readOnlyAdmin\n    isTeam\n    entityType\n    privateOnly\n    storageBytes\n    codeSavingEnabled\n    defaultAccess\n    isPaid\n    members {\n      id\n      admin\n      pending\n      email\n      username\n      name\n      photoUrl\n      accountType\n      apiKey\n    }\n  }\n}\n'
CREATE_TEAM_GQL = '\nmutation CreateTeam($teamName: String!, $teamAdminUserName: String) {\n  result: createTeam(\n    input: {teamName: $teamName, teamAdminUserName: $teamAdminUserName}\n  ) {\n    entity {\n      id\n      name\n      available\n      photoUrl\n      limits\n    }\n  }\n}\n'
CREATE_INVITE_GQL = '\nmutation CreateInvite($entity: String!, $email: String, $username: String, $admin: Boolean) {\n  result: createInvite(\n    input: {entityName: $entity, email: $email, username: $username, admin: $admin}\n  ) {\n    invite {\n      id\n      name\n      email\n      createdAt\n      toUser {\n        name\n      }\n    }\n  }\n}\n'
DELETE_INVITE_GQL = '\nmutation DeleteInvite($id: String, $entity: String) {\n  result: deleteInvite(input: {id: $id, entityName: $entity}) {\n    success\n  }\n}\n'
CREATE_SERVICE_ACCOUNT_GQL = '\nmutation CreateServiceAccount($entity: String!, $description: String!) {\n  result: createServiceAccount(\n    input: {description: $description, entityName: $entity}\n  ) {\n    user {\n      id\n    }\n  }\n}\n'
SEARCH_USERS_GQL = '\nquery SearchUsers($query: String) {\n  users(query: $query) {\n    edges {\n      node {\n        ...UserFragment\n      }\n    }\n  }\n}\n\nfragment ApiKeyFragment on ApiKey {\n  id\n  name\n  description\n}\n\nfragment UserFragment on User {\n  id\n  name\n  username\n  email\n  admin\n  flags\n  entity\n  deletedAt\n  apiKeys {\n    edges {\n      node {\n        ...ApiKeyFragment\n      }\n    }\n  }\n  teams {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
GET_VIEWER_GQL = '\nquery GetViewer {\n  viewer {\n    ...UserFragment\n  }\n}\n\nfragment ApiKeyFragment on ApiKey {\n  id\n  name\n  description\n}\n\nfragment UserFragment on User {\n  id\n  name\n  username\n  email\n  admin\n  flags\n  entity\n  deletedAt\n  apiKeys {\n    edges {\n      node {\n        ...ApiKeyFragment\n      }\n    }\n  }\n  teams {\n    edges {\n      node {\n        name\n      }\n    }\n  }\n}\n'
GET_DEFAULT_ENTITY_GQL = '\nquery GetDefaultEntity {\n  viewer {\n    id\n    entity\n  }\n}\n'
CREATE_USER_FROM_ADMIN_GQL = '\nmutation CreateUserFromAdmin($email: String!, $admin: Boolean) {\n  result: createUser(input: {email: $email, admin: $admin}) {\n    user {\n      ...UserInfoFragment\n    }\n  }\n}\n\nfragment UserInfoFragment on User {\n  id\n  name\n  username\n  email\n  admin\n}\n'
DELETE_API_KEY_GQL = '\nmutation DeleteApiKey($id: String!) {\n  result: deleteApiKey(input: {id: $id}) {\n    success\n  }\n}\n'
GENERATE_API_KEY_GQL = '\nmutation GenerateApiKey($description: String) {\n  result: generateApiKey(input: {description: $description}) {\n    apiKey {\n      ...ApiKeyFragment\n    }\n  }\n}\n\nfragment ApiKeyFragment on ApiKey {\n  id\n  name\n  description\n}\n'
